    var envStageEl = document.getElementById('envops-stage');
    if (envStageEl) {
        envStageEl.addEventListener('click', function (e) {
            var uiActor = _envManualActorId();
            var inspectorActionEl = e.target.closest('[data-env-inspector-action]');
            if (inspectorActionEl) {
                var inspectorObj = _envInspectorCurrentObject();
                if (_envHandleInspectorAction(inspectorActionEl.getAttribute('data-env-inspector-action') || '', inspectorObj, uiActor, inspectorActionEl)) {
                    return;
                }
            }
            var inspectorSectionEl = e.target.closest('[data-env-inspector-section]');
            if (inspectorSectionEl) {
                _envInspectorSetActiveSection(inspectorSectionEl.getAttribute('data-env-inspector-section') || '');
                return;
            }
            var actionEl = e.target.closest('[data-env-action]');
            if (actionEl) {
                var action = actionEl.getAttribute('data-env-action') || '';
                if (action === 'scene-close-panel') {
                    _envCloseHtmlPanel(uiActor, 'stage panel close');
                    return;
                }
                if (action === 'scene-nav-back') {
                    _envSceneNavigateBack(uiActor, _envHtmlPanelState.objectKey || '', 'stage navigation back');
                    return;
                }
                if (action === 'scene-object') {
                    var sceneObj = _envSceneObjectByKey(actionEl.getAttribute('data-env-object-key') || '');
                    if (!sceneObj) return;
                    _envSelectSceneObject(sceneObj, uiActor, 'stage_dom');
                    return;
                }
                if (action === 'scene-menu-item') {
                    var menuObj = _envSceneObjectByKey(actionEl.getAttribute('data-env-object-key') || '');
                    if (!menuObj) return;
                    _envExecuteSceneMenuItem(menuObj, actionEl.getAttribute('data-env-menu-index') || '0', 'stage_menu', { actor: uiActor });
                    return;
                }
                if (action === 'refresh-health') {
                    _envRequestRunHistory('health refresh', true);
                    _envRequestHealth('manual refresh', true);
                    renderEnvironmentView();
                    return;
                }
                if (action === 'toggle-replay') {
                    _envQueueControl('toggle_replay', '', uiActor, 'stage replay toggle');
                    return;
                }
                if (action === 'replay-prev') {
                    _envQueueControl('replay_prev', '', uiActor, 'stage replay previous');
                    return;
                }
                if (action === 'replay-next') {
                    _envQueueControl('replay_next', '', uiActor, 'stage replay next');
                    return;
                }
                if (action === 'set-replay-mode') {
                    _envQueueControl('set_replay_mode', actionEl.getAttribute('data-env-replay-mode') || 'samples', uiActor, 'stage replay mode');
                    return;
                }
                if (action === 'replay-focus') {
                    _envQueueControl('focus_replay', actionEl.getAttribute('data-env-replay-index') || '0', uiActor, 'stage replay focus');
                    return;
                }
            }
            var focusEl = e.target.closest('[data-env-focus-kind]');
            if (!focusEl) {
                if (_envInspectorState.active
                    && !e.target.closest('[data-env-inspector-root]')
                    && !e.target.closest('.envops-scene-panel')
                    && !e.target.closest('[data-env-action="scene-object"]')
                    && !e.target.closest('[data-env-action="scene-menu-item"]')) {
                    _envCloseInspector(uiActor, 'click-away');
                }
                return;
            }
            var focusKind = focusEl.getAttribute('data-env-focus-kind') || 'workflow';
            var focusId = focusEl.getAttribute('data-env-focus-id') || '';
            var command = _envFocusCommandForKind(focusKind);
            if (!command) return;
            _envQueueControl(command, focusId, uiActor, 'habitat focus', { kind: focusKind });
        });
    }

